import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { Interval } from '@nestjs/schedule';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import { Queue } from 'bullmq';
import { Gauge } from 'prom-client';
import { ANALYTICS_QUEUE } from './queue.config';

/**
 * Periodically reports BullMQ queue depth to Prometheus (README §2.6 Monitoring,
 * §2.7 worker autoscaling signal). Feeds the "queue backpressure" alert (§2.6).
 */
@Injectable()
export class QueueMetricsService {
  private readonly logger = new Logger(QueueMetricsService.name);

  constructor(
    @InjectQueue(ANALYTICS_QUEUE) private readonly queue: Queue,
    @InjectMetric('smartcart_bullmq_queue_depth')
    private readonly depth: Gauge<string>,
  ) {}

  @Interval(15_000)
  async report(): Promise<void> {
    try {
      const waiting = await this.queue.getWaitingCount();
      this.depth.set({ queue: ANALYTICS_QUEUE }, waiting);
    } catch (err) {
      this.logger.warn(`Failed to read queue depth: ${String(err)}`);
    }
  }
}
